#!/usr/bin/env python3\n\"\"\"\nComprehensive test runner for ViperMind Python Tutor\nRuns all tests in the correct order and provides detailed reporting\n\"\"\"\n\nimport os\nimport sys\nimport subprocess\nimport time\nfrom typing import Dict, List, Tuple\nfrom datetime import datetime\n\nclass TestRunner:\n    \"\"\"Comprehensive test runner for the ViperMind system\"\"\"\n    \n    def __init__(self):\n        self.test_results = {}\n        self.start_time = None\n        self.end_time = None\n    \n    def run_all_tests(self) -> bool:\n        \"\"\"Run all tests in the correct order\"\"\"\n        print(\"🧪 ViperMind Python Tutor - Comprehensive Test Suite\")\n        print(\"=\" * 70)\n        print(f\"Started at: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\")\n        print()\n        \n        self.start_time = time.time()\n        \n        # Define test categories and their tests\n        test_categories = [\n            {\n                \"name\": \"Unit Tests - Database Models\",\n                \"tests\": [\n                    (\"test_models.py\", \"Database model validation\"),\n                ],\n                \"required\": True\n            },\n            {\n                \"name\": \"Unit Tests - Authentication System\",\n                \"tests\": [\n                    (\"test_auth_system.py\", \"JWT authentication and user management\"),\n                ],\n                \"required\": True\n            },\n            {\n                \"name\": \"API Integration Tests\",\n                \"tests\": [\n                    (\"test_curriculum_api.py\", \"Curriculum management API\"),\n                    (\"test_assessment_api.py\", \"Assessment generation and submission API\"),\n                    (\"test_agent_system.py\", \"LangGraph agent system\"),\n                ],\n                \"required\": True\n            },\n            {\n                \"name\": \"Feature Integration Tests\",\n                \"tests\": [\n                    (\"test_full_assessment_flow.py\", \"Complete assessment workflow\"),\n                    (\"test_retake_system.py\", \"Assessment retake and attempt management\"),\n                ],\n                \"required\": True\n            },\n            {\n                \"name\": \"AI Quality Validation Tests\",\n                \"tests\": [\n                    (\"test_ai_quality_validation.py\", \"AI-generated content quality validation\"),\n                ],\n                \"required\": False  # May fail if OpenAI API is not available\n            },\n            {\n                \"name\": \"End-to-End Integration Tests\",\n                \"tests\": [\n                    (\"test_integration_user_journeys.py\", \"Complete user journey workflows\"),\n                ],\n                \"required\": False  # May fail if system is not fully running\n            },\n            {\n                \"name\": \"Performance Tests\",\n                \"tests\": [\n                    (\"test_performance.py\", \"System performance and load testing\"),\n                ],\n                \"required\": False  # May fail if system is under load\n            }\n        ]\n        \n        # Run frontend tests if available\n        frontend_available = self._check_frontend_tests()\n        if frontend_available:\n            test_categories.append({\n                \"name\": \"Frontend Unit Tests\",\n                \"tests\": [\n                    (\"npm test -- --coverage --watchAll=false\", \"React component tests\"),\n                ],\n                \"required\": False,\n                \"frontend\": True\n            })\n        \n        overall_success = True\n        \n        for category in test_categories:\n            print(f\"\\n📂 {category['name']}\")\n            print(\"-\" * 50)\n            \n            category_success = True\n            \n            for test_file, description in category['tests']:\n                success = self._run_test(test_file, description, category.get('frontend', False))\n                \n                if not success:\n                    category_success = False\n                    if category['required']:\n                        overall_success = False\n            \n            # Category summary\n            status = \"✅ PASSED\" if category_success else \"❌ FAILED\"\n            requirement = \"(Required)\" if category['required'] else \"(Optional)\"\n            print(f\"\\n{status} {category['name']} {requirement}\")\n        \n        self.end_time = time.time()\n        \n        # Final summary\n        self._print_final_summary(overall_success)\n        \n        return overall_success\n    \n    def _run_test(self, test_file: str, description: str, is_frontend: bool = False) -> bool:\n        \"\"\"Run a single test file\"\"\"\n        print(f\"\\n🔍 {description}\")\n        print(f\"   Running: {test_file}\")\n        \n        start_time = time.time()\n        \n        try:\n            if is_frontend:\n                # Run frontend test\n                result = subprocess.run(\n                    test_file.split(),\n                    cwd=\"../frontend\",\n                    capture_output=True,\n                    text=True,\n                    timeout=300  # 5 minute timeout\n                )\n            else:\n                # Run backend test\n                result = subprocess.run(\n                    [sys.executable, test_file],\n                    capture_output=True,\n                    text=True,\n                    timeout=300  # 5 minute timeout\n                )\n            \n            end_time = time.time()\n            duration = end_time - start_time\n            \n            if result.returncode == 0:\n                print(f\"   ✅ PASSED ({duration:.1f}s)\")\n                self.test_results[test_file] = {\n                    \"status\": \"PASSED\",\n                    \"duration\": duration,\n                    \"description\": description\n                }\n                return True\n            else:\n                print(f\"   ❌ FAILED ({duration:.1f}s)\")\n                print(f\"   Error: {result.stderr.strip()[:200]}...\" if result.stderr else \"\")\n                self.test_results[test_file] = {\n                    \"status\": \"FAILED\",\n                    \"duration\": duration,\n                    \"description\": description,\n                    \"error\": result.stderr.strip()[:500]\n                }\n                return False\n                \n        except subprocess.TimeoutExpired:\n            print(f\"   ⏰ TIMEOUT (>300s)\")\n            self.test_results[test_file] = {\n                \"status\": \"TIMEOUT\",\n                \"duration\": 300,\n                \"description\": description\n            }\n            return False\n            \n        except Exception as e:\n            print(f\"   💥 ERROR: {str(e)}\")\n            self.test_results[test_file] = {\n                \"status\": \"ERROR\",\n                \"duration\": 0,\n                \"description\": description,\n                \"error\": str(e)\n            }\n            return False\n    \n    def _check_frontend_tests(self) -> bool:\n        \"\"\"Check if frontend tests are available\"\"\"\n        frontend_path = \"../frontend\"\n        package_json_path = os.path.join(frontend_path, \"package.json\")\n        \n        if os.path.exists(package_json_path):\n            # Check if test files exist\n            test_dir = os.path.join(frontend_path, \"src\", \"components\", \"__tests__\")\n            if os.path.exists(test_dir) and os.listdir(test_dir):\n                return True\n        \n        return False\n    \n    def _print_final_summary(self, overall_success: bool):\n        \"\"\"Print final test summary\"\"\"\n        print(\"\\n\" + \"=\" * 70)\n        print(\"📊 FINAL TEST SUMMARY\")\n        print(\"=\" * 70)\n        \n        total_duration = self.end_time - self.start_time\n        \n        # Count results\n        passed = sum(1 for r in self.test_results.values() if r['status'] == 'PASSED')\n        failed = sum(1 for r in self.test_results.values() if r['status'] == 'FAILED')\n        timeout = sum(1 for r in self.test_results.values() if r['status'] == 'TIMEOUT')\n        error = sum(1 for r in self.test_results.values() if r['status'] == 'ERROR')\n        total = len(self.test_results)\n        \n        print(f\"\\n📈 Test Statistics:\")\n        print(f\"   Total Tests: {total}\")\n        print(f\"   Passed: {passed} ✅\")\n        print(f\"   Failed: {failed} ❌\")\n        print(f\"   Timeout: {timeout} ⏰\")\n        print(f\"   Error: {error} 💥\")\n        print(f\"   Success Rate: {(passed/total*100):.1f}%\" if total > 0 else \"   Success Rate: 0%\")\n        print(f\"   Total Duration: {total_duration:.1f}s\")\n        \n        # Detailed results\n        print(f\"\\n📋 Detailed Results:\")\n        for test_file, result in self.test_results.items():\n            status_icon = {\n                'PASSED': '✅',\n                'FAILED': '❌',\n                'TIMEOUT': '⏰',\n                'ERROR': '💥'\n            }.get(result['status'], '❓')\n            \n            print(f\"   {status_icon} {test_file:<35} {result['duration']:>6.1f}s - {result['description']}\")\n            \n            if result['status'] in ['FAILED', 'ERROR'] and 'error' in result:\n                print(f\"      Error: {result['error'][:100]}...\")\n        \n        # Overall result\n        print(f\"\\n{'🎉 ALL TESTS COMPLETED SUCCESSFULLY!' if overall_success else '❌ SOME TESTS FAILED!'}\")\n        \n        if overall_success:\n            print(\"\\n✅ ViperMind System Quality Assurance:\")\n            print(\"   - Database models and relationships validated\")\n            print(\"   - Authentication and security systems tested\")\n            print(\"   - API endpoints and workflows verified\")\n            print(\"   - Assessment generation and scoring validated\")\n            print(\"   - AI agent system functionality confirmed\")\n            print(\"   - User journey workflows tested\")\n            print(\"   - Frontend components validated (if available)\")\n            print(\"   - AI content quality standards met\")\n            print(\"\\n🚀 System is ready for production deployment!\")\n        else:\n            print(\"\\n⚠️  Please review and fix failing tests before deployment.\")\n            print(\"   Check the detailed results above for specific issues.\")\n        \n        print(f\"\\nCompleted at: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\")\n        print(\"=\" * 70)\n\ndef main():\n    \"\"\"Main test runner function\"\"\"\n    # Change to the backend directory\n    script_dir = os.path.dirname(os.path.abspath(__file__))\n    os.chdir(script_dir)\n    \n    # Check if we're in the right directory\n    if not os.path.exists(\"test_models.py\"):\n        print(\"❌ Error: Test files not found. Make sure you're running from the backend directory.\")\n        sys.exit(1)\n    \n    # Run all tests\n    runner = TestRunner()\n    success = runner.run_all_tests()\n    \n    # Exit with appropriate code\n    sys.exit(0 if success else 1)\n\nif __name__ == \"__main__\":\n    main()\n"